const input = $input.first().json;

// Extrair parâmetros
const dentistId = input.dentist_id || input.dentistId || null;
const date = input.date || input.data || null;
const specialty = input.specialty || input.especialidade || null;

if (!date) {
  return [{ json: { error: true, message: 'Data é obrigatória. Informe a data desejada (formato: YYYY-MM-DD).' } }];
}

return [{ json: { dentist_id: dentistId, date, specialty } }];

const items = $input.all();
const slots = items.filter(i => i.json.nome_dentista);

if (slots.length === 0) {
  return [{ json: { resultado: 'Nenhum horário disponível encontrado para esta data. Tente outra data ou especialidade.' } }];
}

// Agrupar por dentista
const byDentist = {};
for (const s of slots) {
  const key = s.json.nome_dentista;
  if (!byDentist[key]) {
    byDentist[key] = { specialty: s.json.especialidade, id: s.json.id_dentista, slots: [] };
  }
  byDentist[key].slots.push(`${s.json.slot_inicio.substring(0,5)} - ${s.json.slot_fim.substring(0,5)}`);
}

let resultado = 'Horários disponíveis:\n';
for (const [name, data] of Object.entries(byDentist)) {
  resultado += `\nDr(a). ${name} (${data.specialty || 'Clínica Geral'}) - ID: ${data.id}:\n`;
  resultado += data.slots.map(s => `  • ${s}`).join('\n');
  resultado += '\n';
}

return [{ json: { resultado } }];
